import React from 'react';
import {
  Box,
  Button,
  Heading,
  Text,
} from '@stripe/ui-extension-sdk/ui';

const BRIDGE_URL = 'https://bridge-production-ad61.up.railway.app/app';

/**
 * Bridge Stripe App — Launcher.
 * One button: opens the full Bridge web app in a new tab.
 * The actual app (register, configure, sync) runs on Railway — no iframe issues.
 */
const App = () => {
  const handleOpen = () => {
    // Try multiple approaches to open the URL
    try {
      window.open(BRIDGE_URL, '_blank', 'noopener,noreferrer');
    } catch {
      // Fallback: if window.open is blocked, navigate the iframe
      // (user can manually open from the link below)
    }
  };

  return (
    <Box css={{ padding: 'large' }}>
      <Heading size="xlarge">Bridge</Heading>
      <Text>Sync PayPal transactions into Stripe Payment Records.</Text>
      <Box css={{ marginTop: 'large' }}>
        <Button type="primary" onPress={handleOpen}>
          Open Bridge Dashboard
        </Button>
      </Box>
      <Box css={{ marginTop: 'medium' }}>
        <Text size="small" css={{ color: 'secondary' }}>
          Opens at {BRIDGE_URL}
        </Text>
      </Box>
      <Box css={{ marginTop: 'xlarge' }}>
        <Text size="small" css={{ color: 'secondary' }}>
          Bridge automatically syncs PayPal transactions to Stripe daily.
          Configure credentials in the web dashboard.
        </Text>
      </Box>
    </Box>
  );
};

export default App;
